                                            <div className="text-xs">
                                                {(() => {
                                                    const days = Math.floor((Date.now() - new Date(contact.createdAt || Date.now())) / (1000 * 60 * 60 * 24));
                                                    return days === 0 ? 'Today' : `${days} days ago`;
                                                })()}
