                            <button className="w-full flex items-center space-x-3 px-3 py-2 text-sm text-gray-700 hover:bg-purple-50 rounded-lg transition-colors">
                                <span>⚙️</span>
                                <span>System Settings</span>
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        );
    };

